module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);
  reg [size-1:0] mul_a_reg, mul_b_reg;
  reg [size-1:0] mul_en_out_reg;
  wire [size-1:0] temp [size-1:0];
  reg [size-1:0] sum [size-1:0];
  integer i;

  always @(posedge clk) begin
    if (!rst_n) begin
      mul_en_out_reg <= 1'b0;
    end else begin
      mul_en_out_reg <= mul_en_in;
    end
  end
  assign mul_en_out = mul_en_out_reg[size-1];

  always @(posedge clk) begin
    if (!rst_n) begin
      mul_a_reg <= {size{1'b0}};
      mul_b_reg <= {size{1'b0}};
    end else if (mul_en_in) begin
      mul_a_reg <= mul_a;
      mul_b_reg <= mul_b;
    end
  end

  genvar j;
  generate
    for (j = 0; j < size; j = j + 1) begin : gen_partial_products
      assign temp[j] = mul_b_reg[j] ? {mul_a_reg, {j{1'b0}}} : {size{1'b0}};
    end
  endgenerate

  always @(posedge clk) begin
    if (!rst_n) begin
      for (i = 0; i < size; i = i + 1) begin
        sum[i] <= {size{1'b0}};
      end
    end else if (mul_en_in) begin
      sum[0] <= temp[0];
      for (i = 1; i < size; i = i + 1) begin
        sum[i] <= sum[i-1] + temp[i];
      end
    end
  end

  always @(posedge clk) begin
    if (!rst_n) begin
      mul_out <= {2*size{1'b0}};
    end else if (mul_en_in) begin
      mul_out <= sum[size-1];
    end
  end
endmodule
